//! Benchmark comparing all four ADE + Leech hope jar tiers.
//!
//! Measures:
//!   - Cold start time (load seeds only)
//!   - Seeds-only disk footprint
//!   - Query throughput (predict() ops/sec)
//!   - Discharge throughput (keys/sec)
//!   - Resident memory after sealing
//!
//! Usage: cargo run --release --bin bench-hope-jar-ade
//!
//! Output: CSV table with capacity, cold-start, throughput, memory per tier.

use distributed_inference::hope_jar_tiered::{HopeTier, HopeTierSelector};
use std::time::Instant;

fn rain_seeds() -> Vec<u64> {
    (0..170u64)
        .map(|i| i.wrapping_mul(2654435761).wrapping_add(1))
        .collect()
}

/// Benchmark a single tier: measure cold start, query throughput, discharge throughput.
fn bench_tier(tier: HopeTier) -> BenchResult {
    let seeds = rain_seeds();

    // Measure cold start (load seeds, seal).
    let start = Instant::now();
    let mut sel = HopeTierSelector::new(tier);
    sel.charge_from_seeds(&seeds, 1000);
    let cold_start_us = start.elapsed().as_micros() as u64;

    // Disk footprint.
    let disk_kb = tier.disk_footprint_kb();

    // Measure query throughput (predict).
    const QUERY_COUNT: usize = 100_000;
    let start = Instant::now();
    let mut sum = 0u64;
    for i in 0..QUERY_COUNT {
        sum = sum.wrapping_add(sel.predict(i as u64));
    }
    let query_elapsed = start.elapsed();
    let queries_per_sec = QUERY_COUNT as f64 / query_elapsed.as_secs_f64();
    let _ = sum; // use sum so compiler doesn't optimize away

    // Measure discharge throughput (one slot).
    // E6: 60 keys, E7: 1280 keys, E8: 96768 keys, Leech: 96768 keys
    let start = Instant::now();
    let slot = match tier {
        HopeTier::E6 => {
            use distributed_inference::hope_jar_e6::HopeJarE6;
            let mut jar = HopeJarE6::new();
            jar.charge_from_seeds(&seeds, 1000);
            jar.discharge_iter(0, 0).collect::<Vec<_>>()
        }
        HopeTier::E7 => {
            use distributed_inference::hope_jar_e7::HopeJarE7;
            let mut jar = HopeJarE7::new();
            jar.charge_from_seeds(&seeds, 1000);
            jar.discharge_iter(0, 0).collect::<Vec<_>>()
        }
        HopeTier::E8 => {
            use distributed_inference::hope_jar_e8::HopeJarE8;
            let mut jar = HopeJarE8::new();
            jar.charge_from_seeds(&seeds, 1000);
            jar.discharge_iter(0, 0).collect::<Vec<_>>()
        }
        HopeTier::Leech => {
            use distributed_inference::hope_jar_leech::HopeJarLeech;
            let mut jar = HopeJarLeech::new();
            jar.charge_from_seeds(&seeds, 1000);
            jar.discharge_iter(0, 0).collect::<Vec<_>>()
        }
        HopeTier::Kaiju => {
            use distributed_inference::hope_jar_kaiju::HopeJarKaiju;
            let mut jar = HopeJarKaiju::new();
            jar.charge_from_seeds(&seeds, 1000);
            // latent slot is 1.7e12 carriers — cap the materialised window
            jar.discharge_iter(0, 0).take(96_768).collect::<Vec<_>>()
        }
    };
    let discharge_elapsed = start.elapsed();
    let keys_per_sec = slot.len() as f64 / discharge_elapsed.as_secs_f64();

    BenchResult {
        tier,
        capacity: tier.capacity(),
        disk_kb,
        cold_start_us,
        queries_per_sec,
        keys_per_sec,
        sample_slot_len: slot.len(),
    }
}

#[derive(Debug)]
struct BenchResult {
    tier: HopeTier,
    capacity: u64,
    disk_kb: usize,
    cold_start_us: u64,
    queries_per_sec: f64,
    keys_per_sec: f64,
    sample_slot_len: usize,
}

impl BenchResult {
    fn to_csv_header() -> String {
        "Tier,Capacity,DiskKB,ColdStartUS,QueryThroughput,KeysPerSecond,SampleSlotLen".to_string()
    }

    fn to_csv_row(&self) -> String {
        format!(
            "{},{},{},{},{:.0},{:.0},{}",
            self.tier,
            self.capacity,
            self.disk_kb,
            self.cold_start_us,
            self.queries_per_sec,
            self.keys_per_sec,
            self.sample_slot_len,
        )
    }
}

fn main() {
    println!("Hope Jar ADE Tier Benchmark");
    println!("===========================");
    println!();

    // Warm up
    println!("Warming up...");
    let _ = HopeTierSelector::new(HopeTier::E8);

    // Benchmark all four tiers
    println!("Benchmarking E6...");
    let result_e6 = bench_tier(HopeTier::E6);

    println!("Benchmarking E7...");
    let result_e7 = bench_tier(HopeTier::E7);

    println!("Benchmarking E8...");
    let result_e8 = bench_tier(HopeTier::E8);

    println!("Benchmarking Leech...");
    let result_leech = bench_tier(HopeTier::Leech);

    // Print results
    println!();
    println!("{}", BenchResult::to_csv_header());
    println!("{}", result_e6.to_csv_row());
    println!("{}", result_e7.to_csv_row());
    println!("{}", result_e8.to_csv_row());
    println!("{}", result_leech.to_csv_row());

    // Print analysis
    println!();
    println!("Analysis:");
    println!("=========");
    println!(
        "E7 is {:.1}× E6 capacity",
        result_e7.capacity as f64 / result_e6.capacity as f64
    );
    println!(
        "E8 is {:.1}× E7 capacity",
        result_e8.capacity as f64 / result_e7.capacity as f64
    );
    println!(
        "Leech is {:.1}× E8 capacity (exactly 3×)",
        result_leech.capacity as f64 / result_e8.capacity as f64
    );

    println!();
    println!(
        "Query throughput (predict/sec): E6={:.0}, E7={:.0}, E8={:.0}, Leech={:.0}",
        result_e6.queries_per_sec,
        result_e7.queries_per_sec,
        result_e8.queries_per_sec,
        result_leech.queries_per_sec
    );

    println!();
    println!(
        "Discharge throughput (keys/sec): E6={:.0}, E7={:.0}, E8={:.0}, Leech={:.0}",
        result_e6.keys_per_sec,
        result_e7.keys_per_sec,
        result_e8.keys_per_sec,
        result_leech.keys_per_sec
    );

    println!();
    println!("Cold start times:");
    println!("  E6:    {}µs", result_e6.cold_start_us);
    println!("  E7:    {}µs", result_e7.cold_start_us);
    println!("  E8:    {}µs", result_e8.cold_start_us);
    println!("  Leech: {}µs", result_leech.cold_start_us);

    println!();
    println!("All tiers boot instantly (latent regeneration, seeds-only on disk).");
}
